import React, { useState } from 'react';
import classNames from 'classnames';
import './Header.scss';

export const Header = () => {
  const [menu, setMenu] = useState('false');

  const menuItems = [
    'Plan you vaccine', 'Covid-19', 'Politics',
    'U.S.News', 'Opinion', 'World', 'Busness', 'Tech',
  ];

  return (
    <header className="Header">
      <div className="container">
        <h1 className="Header-Logo">News</h1>
        <div className="Header-Menu Menu">
          <ul className={classNames('Menu-List', {
            visibility: menu

          })}>
            {menuItems.map(item => (
              <li className="Menu-Item" key={item}>
                {item.toUpperCase()}
              </li>
            ))}
          </ul>
          <button
            type="button"
            className="button"
            onClick={() => setMenu(!menu)}
          >
            {menu ? 'X' : 'O' }
          </button>
        </div>
      </div>
      {/* <h1 className="Header-Logo">News</h1>
      <div className="Header-Menu Menu">
        <ul className="Menu-List">
          {menuItems.map(item => (
            <li className="Menu-Item" key={item}>
              {item.toUpperCase()}
            </li>
          ))}
        </ul>

        <button type="button" className="button">X</button>
      </div> */}
      {/* <button type="button" className="button">X</button> */}
      <div>
        <form>
          <button type="button" className="button-search" />
          <input />
          <button type="button" className="button">D</button>
        </form>
        <nav className="Header-Nav Nav">
          <a href="#home" className="Nav-Item">Home</a>
          <a href="#articles" className="Nav-Item">Articles</a>
        </nav>
      </div>
    </header>
  );
};
